const getAdminKpis = `-- name: GetAdminKpis :one
WITH
training_counts AS (
    SELECT COUNT(*) AS total_trainings
    FROM trainings
    WHERE is_active = 1
),

nomination_stats AS (
    SELECT
        COUNT(*) FILTER (WHERE status IN ('ENROLLED', 'COMPLETED', 'ATTENDED'))
            AS total_participants,
        COUNT(*) FILTER (WHERE status = 'COMPLETED') AS completed_count,
        COUNT(*) FILTER (WHERE status IN ('ENROLLED', 'COMPLETED', 'ATTENDED'))
            AS enrolled_count
    FROM nominations
),

mandays_calc AS (
    SELECT
        COALESCE(
            SUM((JULIANDAY(t.end_date) - JULIANDAY(t.start_date) + 1)), 0.0
        )
            AS total_man_days
    FROM trainings t
    JOIN nominations n ON t.id = n.training_id
    WHERE t.is_active = 1 AND n.status IN ('ENROLLED', 'COMPLETED', 'ATTENDED')
)

SELECT
    tc.total_trainings,
    ns.total_participants,
    ns.completed_count,
    ns.enrolled_count,
    mc.total_man_days
FROM training_counts tc, nomination_stats ns, mandays_calc mc
`

type GetAdminKpisRow struct {
	TotalTrainings    int64       `json:"total_trainings"`
	TotalParticipants int64       `json:"total_participants"`
	CompletedCount    int64       `json:"completed_count"`
	EnrolledCount     int64       `json:"enrolled_count"`
	TotalManDays      interface{} `json:"total_man_days"`
}

// ADMIN STATS
func (q *Queries) GetAdminKpis(ctx context.Context) (GetAdminKpisRow, error) {
	row := q.db.QueryRowContext(ctx, getAdminKpis)
	var i GetAdminKpisRow
	err := row.Scan(
		&i.TotalTrainings,
		&i.TotalParticipants,
		&i.CompletedCount,
		&i.EnrolledCount,
		&i.TotalManDays,
	)
	return i, err
}

